  { id: 3, name: "Notebook", category: "office", rating: 4.7, stock: 19 }
];

console.log(getVisibleProducts(products, "  k  ", "all"));

solution.code:
function getVisibleProducts(products, search, activeCategory) {
  const normalizedSearch = (search ?? "").trim().toLowerCase();
  const normalizedCategory = (activeCategory ?? "all").trim().toLowerCase();

  return products
    .filter((product) => {
      const matchesSearch =
        normalizedSearch.length === 0 ||
        product.name.toLowerCase().includes(normalizedSearch);
      const matchesCategory =
        normalizedCategory === "all" ||
        product.category.toLowerCase() === normalizedCategory;

      return matchesSearch && matchesCategory;
    })
    .map(({ id, name, category, rating }) => ({ id, name, category, rating }))
    .sort((a, b) => {
      if (b.rating !== a.rating) {
        return b.rating - a.rating;
      }

      return a.name.localeCompare(b.name);
    });
}

