const events = [
  { id: "e1", type: "comment", title: "Left a note", createdAt: "2026-04-13T09:30:00Z" },
  { id: "e2", type: "status", title: "Moved to review", createdAt: "2026-04-12T16:10:00Z" },
  { id: "e3", type: "comment", title: "Requested changes", createdAt: "2026-04-13T11:00:00Z" }
];

console.log(buildTimelineSections(events));

solution.code:
function buildTimelineSections(events) {
  if (!Array.isArray(events) || events.length === 0) {
    return [];
  }

  const grouped = new Map();

  for (const event of events) {
    if (!event || !event.createdAt) {
      continue;
    }

    const date = String(event.createdAt).slice(0, 10);
    const currentItems = grouped.get(date) ?? [];

    currentItems.push({
      id: event.id,
      title: event.title,
      type: event.type,
      createdAt: event.createdAt,
    });

    grouped.set(date, currentItems);
  }

  return Array.from(grouped.entries())
    .map(([date, items]) => ({
      date,
      items: items.sort((a, b) => b.createdAt.localeCompare(a.createdAt)),
    }))
    .sort((a, b) => b.date.localeCompare(a.date));
}

