  { id: "o2", customerId: "c2", total: 80, status: "pending" },
  { id: "o3", customerId: "c1", total: 60, status: "completed" }
];

const refunds = [
  { orderId: "o1", amount: 20 }
];

console.log(buildOrderOverview(orders, refunds));

solution.code:
function buildOrderOverview(orders, refunds) {
  const customerSpend = new Map();
  let pendingOrders = 0;
  let completedOrders = 0;
  let completedRevenue = 0;

  for (const order of orders) {
    if (order.status === "pending") {
      pendingOrders += 1;
    }

    if (order.status === "completed") {
      completedOrders += 1;
      completedRevenue += order.total;
      customerSpend.set(
        order.customerId,
        (customerSpend.get(order.customerId) ?? 0) + order.total
      );
    }
  }

  const refundedAmount = refunds.reduce(
    (sum, refund) => sum + refund.amount,
    0
  );

  const topCustomers = Array.from(customerSpend.entries())
    .map(([customerId, spent]) => ({ customerId, spent }))
    .sort((a, b) => b.spent - a.spent)
    .slice(0, 3);

  return {
    totalOrders: orders.length,
    pendingOrders,
    completedOrders,
    refundedAmount,
    netRevenue: completedRevenue - refundedAmount,
    topCustomers,
  };
}

