solution.code:
def resolve_flags(user, environment, flags):
    if not user or not environment or not flags:
        return []

    user_segments = set(user.get("segments", []))
    active_keys = set()

    for flag in flags:
        if not flag.get("enabled"):
            continue

        if environment not in flag.get("environments", []):
            continue

        required_segments = flag.get("segments", [])
        if required_segments and user_segments.isdisjoint(required_segments):
            continue

        active_keys.add(flag["key"])

    return sorted(active_keys)

