def allow_request(history, user_id, timestamp, limit, window_seconds):
    copied_history = {
        key: list(values)
        for key, values in history.items()
    }

    recent_requests = [
        entry
        for entry in copied_history.get(user_id, [])
        if timestamp - entry < window_seconds
    ]

    allowed = len(recent_requests) < limit
    if allowed:
        recent_requests.append(timestamp)

    copied_history[user_id] = recent_requests
    return allowed, copied_history

