import java.util.Comparator;
import java.util.List;
import java.util.stream.Collectors;

class Job {
    String id;
    String status;
    int retryCount;
    long nextRetryAt;

    Job(String id, String status, int retryCount, long nextRetryAt) {
        this.id = id;
        this.status = status;
        this.retryCount = retryCount;
        this.nextRetryAt = nextRetryAt;
    }
}

public class Main {
    static List<String> selectRetryableJobs(List<Job> jobs, int maxRetries, long now) {
        return jobs.stream()
            .filter(job -> "failed".equals(job.status))
            .filter(job -> job.retryCount < maxRetries)
            .filter(job -> job.nextRetryAt <= now)
            .sorted(
                Comparator.comparingLong((Job job) -> job.nextRetryAt)
                    .thenComparing(job -> job.id)
            )
            .map(job -> job.id)
            .collect(Collectors.toList());
    }
}
